const PREGUNTAS_BANCO = [
  { id: 1, pregunta: "Respecto de los dispositivos de control o regulación del tránsito:", opciones: ["Solamente los conductores están obligados a obedecerlos; los peatones pueden ignorarlos.", "Los peatones pueden ignorarlos si no hay vehículos circulando.", "Los conductores y los peatones están obligados a su obediencia, salvo instrucción de la Policía Nacional del Perú asignada al tránsito que indique lo contrario."], correcta: 2 },
  { id: 2, pregunta: "La señal vertical reglamentaria R-6 \"prohibido voltear a la izquierda\", significa que:", opciones: ["Está prohibido voltear a la izquierda, pero el giro en U sí está permitido.", "Solo está prohibido voltear a la izquierda en horario nocturno.", "Está prohibido voltear a la izquierda y, por lo tanto, también está prohibido el giro en U."], correcta: 2 },
  { id: 3, pregunta: "La señal vertical reglamentaria R-3 significa que:", opciones: ["Está permitido girar en cualquier dirección.", "El único sentido de desplazamiento es continuar de frente.", "Se debe reducir la velocidad y girar a la derecha."], correcta: 1, imagen: "imagenes/pregunta 3.webp" },
  { id: 4, pregunta: "En las vías, las marcas en el pavimento que son del tipo central discontinua y de color amarillo significan que:", opciones: ["No está permitido realizar ningún tipo de adelantamiento.", "Solo los vehículos pesados pueden cruzar al otro carril.", "Está permitido cruzar al otro carril para el adelantamiento vehicular, si es que es seguro hacerlo."], correcta: 2 },
  { id: 5, pregunta: "El color ámbar o amarillo del semáforo significa que:", opciones: ["Es una advertencia, pero el conductor puede acelerar para cruzar la intersección.", "El conductor debe continuar con normalidad ya que aún hay tiempo para cruzar.", "Los vehículos deben detenerse antes de ingresar a la intersección si su velocidad y ubicación lo permiten; de lo contrario, deberán cruzar y despejar la intersección."], correcta: 2 },
  { id: 6, pregunta: "Los colores del semáforo tienen el siguiente significado: rojo:____; ámbar o amarillo:_____; verde:________.", opciones: ["Detención - prevención - paso.", "Paso - prevención - detención.", "Prevención - detención - paso."], correcta: 0 },
  { id: 7, pregunta: "¿Qué indica una flecha verde en un semáforo vehicular?", opciones: ["Se puede continuar con precaución únicamente en la dirección de la flecha y desde el carril que esta flecha controla.", "Se puede avanzar en cualquier dirección independientemente del carril.", "La flecha verde equivale a la luz verde circular; se puede avanzar en todos los sentidos."], correcta: 0 },
  { id: 8, pregunta: "La siguiente señal vertical reglamentaria R-53:", opciones: ["Permite detener el vehículo brevemente dentro de la intersección.", "Prohíbe el ingreso a la intersección en todo momento.", "Prohíbe al conductor detener el vehículo dentro del área de la intersección."], correcta: 2, imagen: "imagenes/pregunta 8.jpg" },
  { id: 9, pregunta: "Si llega a una intersección y visualiza el semáforo con una flecha roja hacia la izquierda y la luz circular verde prendidas al mismo tiempo, la acción correcta es:", opciones: ["Detenerse completamente, ya que la flecha roja anula la luz circular verde.", "Girar a la izquierda ya que la luz verde circular tiene prioridad sobre la flecha roja.", "Avanzar, pero el giro a la izquierda está prohibido por la flecha roja."], correcta: 2 },
  { id: 10, pregunta: "Si llega a una intersección donde el semáforo muestra una luz intermitente, qué afirmación es correcta:", opciones: ["Una luz intermitente verde obliga al conductor a detenerse completamente.", "Una luz intermitente ámbar significa que tiene preferencia absoluta y no necesita reducir velocidad.", "Si la luz intermitente es ámbar, tiene preferencia, debiendo reducir la velocidad y continuar con precaución."], correcta: 2 },
  { id: 11, pregunta: "¿La luz intermitente roja es igual que una señal de PARE?", opciones: ["Verdad.", "No, la luz roja intermitente solo obliga a reducir la velocidad.", "No, la luz roja intermitente equivale a ceder el paso sin detenerse."], correcta: 0 },
  { id: 12, pregunta: "Al aproximarse a una intersección con giro permitido a la izquierda, la conducta correcta es:", opciones: ["Girar directamente desde cualquier carril disponible.", "Reducir la velocidad y girar desde el carril en que se encuentre.", "Hacer la señal de volteo a la izquierda con las luces direccionales, ubicar con antelación el vehículo en el carril de circulación de la izquierda y girar con precaución."], correcta: 2 },
  { id: 13, pregunta: "Al cambiar de carril en una vía de un solo sentido con múltiples carriles, ¿cuál es la conducta correcta?", opciones: ["Cambiarse de carril de forma rápida para no obstruir el tráfico.", "Se deben encender las luces direccionales primero, buscar una brecha y realizar el cambio de carril con precaución.", "Basta con mirar por los espejos y cambiar de carril sin usar las direccionales."], correcta: 1 },
  { id: 14, pregunta: "Respecto a los cruces a nivel con vías férreas, señale la afirmación correcta:", opciones: ["Los vehículos que transitan por la vía férrea tienen preferencia de paso sobre los que transitan por la vía que la cruza.", "El conductor puede cruzar la vía férrea si no observa el tren de forma inmediata.", "La preferencia la tiene el vehículo que llegó primero al cruce."], correcta: 0 },
  { id: 15, pregunta: "Ante la señal de color rojo del semáforo y la indicación de continuar la marcha del efectivo de la Policía Nacional del Perú asignado al control del tránsito, corresponde:", opciones: ["Detenerse, ya que el semáforo en rojo siempre prevalece sobre cualquier indicación.", "Continuar la marcha.", "Esperar a que el semáforo cambie a verde antes de avanzar."], correcta: 1 },
  { id: 16, pregunta: "Está prohibido estacionar un vehículo:", opciones: ["Frente a un establecimiento comercial durante el horario de atención.", "En el carril derecho de una avenida en horas de baja circulación.", "Todas las alternativas son correctas."], correcta: 2 },
  { id: 17, pregunta: "La siguiente señal vertical reglamentaria R-29:", opciones: ["Obliga al conductor a disminuir la velocidad y tocar la bocina.", "Indica que solo se permite el uso de la bocina en emergencias.", "Prohíbe el uso de la bocina."], correcta: 2, imagen: "imagenes/pregunta 17.webp" },
  { id: 18, pregunta: "Se le impondrá el pago de una multa y no podrá obtener la licencia de conducir por 3 años a la persona que:", opciones: ["Conduzca un vehículo automotor sin tener licencia de conducir.", "Conduzca con una licencia de categoría inferior a la requerida.", "Conduzca un vehículo con la revisión técnica vencida."], correcta: 0 },
  { id: 19, pregunta: "En el supuesto que se encuentre manejando y un vehículo que tiene la intención de sobrepasarlo o adelantarlo lo alcance, ¿qué debería hacer usted?", opciones: ["Aumentar la velocidad para mantener su posición en la vía.", "No debe aumentar la velocidad hasta que el vehículo lo sobrepase.", "Cambiar de carril para dificultar el adelantamiento."], correcta: 1 },
  { id: 20, pregunta: "¿Cuál de las siguientes afirmaciones es correcta?", opciones: ["El conductor puede superar el límite máximo si las condiciones de la vía lo permiten.", "El conductor debe respetar los límites máximos y mínimos de velocidad establecidos.", "Solo el límite máximo de velocidad es obligatorio; el mínimo es referencial."], correcta: 1 },
  { id: 21, pregunta: "En la circulación vehicular, es correcto afirmar que:", opciones: ["El conductor puede circular por cualquier carril si la vía está despejada.", "Se puede invadir el carril contiguo si se hace con precaución.", "Los vehículos deben circular dentro de las líneas de carril, salvo cuando se realicen las maniobras que indica el Reglamento Nacional de Tránsito."], correcta: 2 },
  { id: 22, pregunta: "En caso de accidentes, el SOAT cubre los daños que sufren:", opciones: ["Los ocupantes y terceros no ocupantes del vehículo.", "Únicamente los ocupantes del vehículo asegurado.", "Solo los daños materiales causados a otros vehículos."], correcta: 0 },
  { id: 23, pregunta: "¿Cuál de los siguientes seguros es exigible para conducir un vehículo automotor?", opciones: ["El seguro vehicular contra todo riesgo.", "El Seguro Obligatorio de Accidentes de Tránsito - SOAT.", "El seguro de responsabilidad civil voluntario."], correcta: 1 },
  { id: 24, pregunta: "Cuándo es obligatorio darle preferencia de paso a un vehículo de emergencia o vehículo oficial:", opciones: ["Siempre que el vehículo de emergencia lleve las luces encendidas, aunque no use la sirena.", "Solo cuando el vehículo de emergencia va en el mismo sentido de circulación.", "Cuando emita señales audibles y visibles."], correcta: 2 },
  { id: 25, pregunta: "Si por el carril por donde está conduciendo se aproxima a un vehículo de transporte escolar que se encuentra detenido, recogiendo o dejando escolares ¿Qué debe hacer?", opciones: ["Detener el vehículo y no continuar la marcha hasta que haya culminado el ascenso o descenso de los escolares.", "Reducir la velocidad y pasar con mucha precaución por el lado izquierdo.", "Tocar el claxon para que los escolares se apresuren y pueda continuar."], correcta: 0 },
  { id: 26, pregunta: "¿Qué significa un triángulo rojo de seguridad colocado en la calzada?", opciones: ["La presencia de un vehículo inmovilizado en la vía pública por alguna circunstancia.", "Que se realizan trabajos de mantenimiento vial próximos.", "Que el conductor del vehículo delantero ha cometido una infracción."], correcta: 0 },
  { id: 27, pregunta: "¿En la conducción vehicular, existe excepción a la obligación de conservar la distancia obligatoria entre vehículos?", opciones: ["Si existe, y es para los cortejos fúnebres, convoyes militares y policiales y caravanas autorizadas.", "No existe ninguna excepción; la distancia de seguridad siempre es obligatoria.", "Sí, cualquier conductor puede reducir la distancia si circula a baja velocidad."], correcta: 0 },
  { id: 28, pregunta: "En intersecciones que no tienen señales de Pare, Ceda el Paso o Semáforo, ¿las vías de doble sentido tienen prioridad de paso respecto a las vías de un solo sentido de igual clasificación?", opciones: ["No, ambas vías tienen la misma prioridad independientemente del número de sentidos.", "Depende de cuál vehículo llegó primero a la intersección.", "Sí."], correcta: 2 },
  { id: 29, pregunta: "Si usted se aproxima a una señal de PARE colocada verticalmente o pintada en la vía, la acción correcta es:", opciones: ["Parar por completo, ceder el paso a los usuarios que tengan preferencia y luego continuar con precaución.", "Reducir la velocidad considerablemente y cruzar si no hay tráfico visible.", "Detenerse solo si hay peatones o vehículos cruzando la intersección."], correcta: 0 },
  { id: 30, pregunta: "¿Cuál es la diferencia entre las señales P-2A y P-1A?", opciones: ["La señal P-1A advierte la presencia de curva pronunciada a la derecha mientras que la P-2A advierte la presencia de curva suave a la derecha.", "La señal P-2A advierte curva pronunciada y la P-1A advierte curva suave, ambas a la derecha.", "Las señales P-1A y P-2A son idénticas; solo cambia el color del fondo."], correcta: 0, imagen: "imagenes/pregunta 30.webp" },
  { id: 31, pregunta: "¿Qué indica la señal R-30F?", opciones: ["Prohíbe circular a más de la velocidad indicada en la señal.", "Indica la velocidad mínima obligatoria en la vía.", "Regula la velocidad máxima permitida en curvas."], correcta: 2, imagen: "imagenes/pregunta 31.jpg" },
  { id: 32, pregunta: "¿Qué indica la siguiente señal R-23?", opciones: ["Circulación exclusiva para vehículos de dos ruedas.", "Solo está permitida la circulación de bicicletas.", "Prohibida la circulación de motocicletas."], correcta: 2, imagen: "imagenes/pregunta 32.png" },
  { id: 33, pregunta: "Si dos vehículos se aproximan simultáneamente a una intersección no regulada (sin señalización) procedentes de vías diferentes, ¿quién tiene preferencia de paso?", opciones: ["El vehículo que circule por la vía más ancha.", "El vehículo que se desplace a menor velocidad.", "El que se aproxime por la derecha del otro."], correcta: 2, imagen: "imagenes/pregunta 33.png" },
  { id: 34, pregunta: "En una intersección no regulada (sin señalización) tiene preferencia de paso:", opciones: ["El vehículo que ingresó primero a la intersección.", "El vehículo que circula por la vía más transitada.", "El vehículo que viene por la derecha del otro."], correcta: 0 },
  { id: 35, pregunta: "En una rotonda, tiene prioridad de paso el vehículo que:", opciones: ["Circula por ella.", "Ingresa a ella desde la derecha.", "Lleva mayor velocidad al momento de ingresar."], correcta: 0 },
  { id: 36, pregunta: "El sobrepaso o adelantamiento de un vehículo en movimiento se efectúa, salvo excepciones, por la ___ retornando el vehículo después de la maniobra a su carril original.", opciones: ["Derecha, siempre que haya espacio suficiente.", "Izquierda.", "Derecha o izquierda, según lo decida el conductor."], correcta: 1 },
  { id: 37, pregunta: "Si un conductor está tomando medicamentos y por ello siente sueño ¿qué debe hacer?", opciones: ["Abstenerse de manejar.", "Conducir a velocidad reducida y con las ventanas abiertas.", "Tomar café o bebidas energizantes antes de conducir."], correcta: 0 },
  { id: 38, pregunta: "Son documentos que deben portarse obligatoriamente, durante la conducción del vehículo, y exhibirse cuando la autoridad competente lo solicite:", opciones: ["Licencia de conducir, tarjeta de propiedad y póliza del seguro vehicular.", "Documento de identidad, SOAT vigente (puede ser virtual) y tarjeta de identificación vehicular.", "Solo la licencia de conducir y el SOAT vigente."], correcta: 1 },
  { id: 39, pregunta: "La siguiente señal indica:", opciones: ["Que solo las motocicletas pueden circular por la vía o carril.", "Que está prohibida la circulación de motocicletas.", "Que las motocicletas deben circular únicamente por la berma."], correcta: 0, imagen: "imagenes/prgunta 39.webp" },
  { id: 40, pregunta: "Al cambiar de dirección, un conductor debe:", opciones: ["Activar las luces de emergencia durante toda la maniobra.", "Reducir la velocidad y girar sin usar las luces direccionales si la vía está despejada.", "Señalizar toda la maniobra hasta su culminación."], correcta: 2 },
  { id: 41, pregunta: "¿Está permitido conducir un vehículo con el motor en punto neutro?", opciones: ["Sí, es permitido para ahorrar combustible en bajadas.", "No, está prohibido.", "Solo está permitido en zonas de pendiente descendente."], correcta: 1 },
  { id: 42, pregunta: "Si la licencia de conducir no se encuentra vigente, los vehículos que autoriza a conducir dicha licencia:", opciones: ["Pueden conducirse solo en zonas urbanas y a baja velocidad.", "Pueden conducirse si el conductor tiene otro tipo de habilitación.", "No podrán ser conducidos."], correcta: 2 },
  { id: 43, pregunta: "De acuerdo con el sistema de control de licencias de conducir por puntos:", opciones: ["Todas las infracciones tienen el mismo puntaje.", "Determinadas infracciones suman puntos.", "Los puntos se acumulan de forma indefinida sin consecuencias adicionales."], correcta: 1 },
  { id: 44, pregunta: "¿Cuál es la consecuencia de acumular 100 puntos en la licencia de conducir en un período de 24 meses?", opciones: ["Cancelación definitiva de la licencia de conducir.", "Suspensión de licencia de conducir.", "Multa equivalente al doble de la UIT vigente."], correcta: 1 },
  { id: 45, pregunta: "Se entiende por carril a la:", opciones: ["Zona lateral pavimentada destinada al estacionamiento de vehículos.", "Parte de la calzada destinada al tránsito de una fila de vehículos.", "Franja de la berma habilitada para la circulación de motos."], correcta: 1 },
  { id: 46, pregunta: "Se entiende por línea de parada a:", opciones: ["La señal horizontal pintada en la berma que indica el inicio de la zona de estacionamiento.", "La línea transversal marcada en la calzada antes de la intersección, que indica al conductor el límite para detener el vehículo.", "La línea longitudinal que separa los carriles de circulación opuesta."], correcta: 1 },
  { id: 47, pregunta: "La siguiente señal vertical reglamentaria P-17A, indica:", opciones: ["Reducción de la calzada solo por el lado izquierdo.", "Reducción de la calzada solo por el lado derecho.", "Reducción de la calzada en ambos lados."], correcta: 2, imagen: "imagenes/pregunta 47.jpg" },
  { id: 48, pregunta: "En caso de encontrar marcación de doble línea amarilla compuesta por un trazo continuo y otro trazo discontinuo en una vía de doble sentido, ¿qué se debe hacer?", opciones: ["Siempre está prohibido adelantar, sin importar cuál trazo está de su lado.", "Respetar la línea que está de su lado (si es continua, no adelantar; si es discontinua, está permitido adelantar).", "Se puede adelantar por cualquiera de los dos lados si no hay vehículos en sentido contrario."], correcta: 1 },
  { id: 49, pregunta: "Se define como zona rígida al:", opciones: ["Área de la vía en la que se prohíbe el estacionamiento de vehículos.", "Carril exclusivo para vehículos de emergencia.", "Zona donde está prohibida la circulación de vehículos pesados."], correcta: 0 },
  { id: 50, pregunta: "La posición de frente o de espaldas ejecutada por el efectivo de la Policía Nacional del Perú asignado al control de tránsito significa:", opciones: ["Paso libre para todos los vehículos en todas las direcciones.", "Obligación de detenerse de quien así lo enfrente.", "Reducción de velocidad obligatoria sin necesidad de detenerse."], correcta: 1 },
  { id: 51, pregunta: "Siempre que no exista una señal de límite de velocidad, en zonas urbanas el límite máximo de velocidad en calles y jirones es de:", opciones: ["40 km/h.", "50 km/h.", "30 km/h."], correcta: 0 },
  { id: 52, pregunta: "Siempre que no exista una señal de límite de velocidad, en zonas urbanas el límite máximo de velocidad en avenidas es de:", opciones: ["50 km/h.", "60 km/h.", "80 km/h."], correcta: 1 },
  { id: 53, pregunta: "Siempre que no exista una señal de límite de velocidad en zonas urbanas, el límite máximo de velocidad en zona escolar es de:", opciones: ["20 km/h.", "40 km/h.", "30 km/h."], correcta: 2 },
  { id: 54, pregunta: "Siempre que no exista una señal de límite de velocidad en carreteras, el límite máximo de velocidad para automóviles, camionetas y motocicletas es de:", opciones: ["120 km/h.", "100 km/h.", "90 km/h."], correcta: 1 },
  { id: 55, pregunta: "Siempre que no exista una señal de límite de velocidad en carreteras, el límite máximo de velocidad es de:", opciones: ["80 km/h. para automóviles, camionetas y motocicletas.", "120 km/h. para automóviles, camionetas y motocicletas.", "100 km/h. para automóviles, camionetas y motocicletas."], correcta: 2 },
  { id: 56, pregunta: "Siempre que no exista una señal de límite de velocidad mínima, el límite mínimo de velocidad en zona urbana y en carreteras es de:", opciones: ["El 60% de la velocidad máxima establecida para cada tipo de vía.", "El 30% de la velocidad máxima establecida para cada tipo de vía.", "La mitad de la velocidad máxima establecida para cada tipo de vía."], correcta: 2 },
  { id: 57, pregunta: "¿Cuál es la sanción por conducir con presencia de alcohol en la sangre en proporción mayor a lo previsto en el Código Penal, o bajo los efectos de estupefacientes, narcóticos y/o alucinógenos comprobado con el examen respectivo, o por negarse al mismo y que haya participado en un accidente de tránsito?", opciones: ["Suspensión de la licencia de conducir por 3 años y multa.", "Multa, cancelación de la licencia de conducir e inhabilitación definitiva para obtener una licencia de conducir.", "Multa y suspensión de licencia por 5 años."], correcta: 1 },
  { id: 58, pregunta: "¿Cuál es la sanción si en un operativo de alcoholemia usted es intervenido y se comprueba que ha consumido alcohol por encima del límite legal, o está conduciendo bajo los efectos de estupefacientes, narcóticos y/o alucinógenos comprobada con el examen respectivo?", opciones: ["Multa y suspensión de la licencia de conducir por 3 años.", "Solo se aplica una amonestación si es la primera vez.", "Cancelación definitiva de la licencia sin posibilidad de recuperarla."], correcta: 0 },
  { id: 59, pregunta: "La frecuencia de la inspección técnica de una moto (categoría L3) y de un sidecar (categoría L4) es:", opciones: ["Cada dos años.", "Cada seis meses.", "Cada año."], correcta: 2 },
  { id: 60, pregunta: "¿Cuál es el plazo de vigencia del SOAT?", opciones: ["6 meses.", "1 año.", "2 años."], correcta: 1 },
  { id: 61, pregunta: "Si ocurre un accidente de tránsito, ¿qué obligación tiene el conductor, el propietario del vehículo o el prestador del servicio de transporte?", opciones: ["Dar aviso a la compañía de seguros y dejar constancia en la delegación de la Policía Nacional del Perú más cercana.", "Solo están obligados a prestar auxilio a los heridos; el informe policial es voluntario.", "Retirarse del lugar si no hay heridos para no interrumpir el tráfico."], correcta: 0 },
  { id: 62, pregunta: "Si una licencia de conducir consigna alguna restricción, es correcto afirmar que:", opciones: ["La restricción es una recomendación; no es de carácter obligatorio.", "Es una obligación cumplir con la restricción.", "Las restricciones aplican únicamente en zonas urbanas."], correcta: 1 },
  { id: 63, pregunta: "La señal preventiva P-33A, significa:", opciones: ["Proximidad a una zona de frenado de emergencia.", "Señal de proximidad de un reductor de velocidad tipo resalto.", "Indica que la vía está próxima a terminar."], correcta: 1, imagen: "imagenes/pregunta 63.jpg" },
  { id: 64, pregunta: "¿Está permitido usar la bocina de su vehículo para advertir al conductor del vehículo que circula delante, que será adelantado?", opciones: ["No, está prohibido.", "Sí, es una buena práctica de conducción preventiva.", "Solo está permitido en carreteras fuera de zonas urbanas."], correcta: 0 },
  { id: 65, pregunta: "Si observa que se aproxima una ambulancia sin las luces especiales encendidas y sin sirena, es correcto afirmar que:", opciones: ["Igual debemos darle preferencia de paso por ser vehículo de emergencia.", "Debemos cederle el paso si se aproxima por la misma vía.", "No estamos obligados a darle preferencia de paso."], correcta: 2 },
  { id: 66, pregunta: "Si se encuentra en una intersección y se enciende la luz verde del semáforo y observa que en la calle transversal hay vehículos o personas despejando la intersección, ¿qué debe hacer?", opciones: ["Avanzar lentamente para presionar a los vehículos o personas a que despejen la vía.", "Tocar el claxon para alertar que el semáforo está en verde y debe avanzar.", "No iniciar la marcha hasta que el vehículo o las personas terminen de cruzar."], correcta: 2 },
  { id: 67, pregunta: "En señalética vial, el color ____ en el pavimento es utilizado para carriles de tráfico en sentido opuesto y el color ____ en el pavimento es utilizado como separador de carriles de tráfico en el mismo sentido.", opciones: ["Blanco - amarillo.", "Amarillo - blanco.", "Blanco - blanco discontinuo."], correcta: 1 },
  { id: 68, pregunta: "Si una fila de escolares cruza la calzada fuera del crucero peatonal, ¿qué acción se debe tomar?", opciones: ["Continuar la marcha ya que los peatones deben cruzar solo por el paso peatonal.", "Parar y ceder el paso.", "Reducir la velocidad pero no es obligatorio detenerse completamente."], correcta: 1 },
  { id: 69, pregunta: "Si se aproxima a una zona escolar, ¿qué acción debe realizar?", opciones: ["Activar las luces de emergencia y circular con normalidad.", "Disminuir la velocidad a 30 Km/h.", "Tocar la bocina para alertar a los escolares de su presencia."], correcta: 1 },
  { id: 70, pregunta: "Tienen el objetivo de notificar a los usuarios las limitaciones, prohibiciones o restricciones en el uso de la vía.", opciones: ["Señales preventivas.", "Señales informativas.", "Señales reguladoras o de reglamentación."], correcta: 2 },
  { id: 71, pregunta: "Tienen el propósito de advertir a los usuarios sobre la existencia y naturaleza de un peligro en la vía.", opciones: ["Señales informativas de servicio.", "Señales preventivas.", "Señales reguladoras o de reglamentación."], correcta: 1 },
  { id: 72, pregunta: "Es una infracción de tránsito:", opciones: ["Detenerse completamente ante una señal de PARE.", "Todas las alternativas son correctas.", "Usar las luces de emergencia ante una avería del vehículo."], correcta: 1 },
  { id: 73, pregunta: "¿Qué debería hacer el conductor al acercarse a una señal de 'CEDA EL PASO' en una intersección?", opciones: ["Disminuir la velocidad, parar si es necesario y ceder el paso a los peatones o vehículos que circulan por la vía transversal.", "Detenerse completamente siempre, igual que ante una señal de PARE.", "Continuar la marcha si no hay peatones visibles en la intersección."], correcta: 0 },
  { id: 74, pregunta: "No se debe conducir un vehículo:", opciones: ["Todas son correctas.", "Con el nivel de combustible bajo.", "Con la radio o música encendida."], correcta: 0 },
  { id: 75, pregunta: "¿Qué debe hacer si se aproxima a una intersección sin semáforo y sin presencia de la Policía de Tránsito, y observa que un peatón está cruzando por el paso peatonal?", opciones: ["Tocar el claxon para advertir al peatón que va a cruzar.", "Detener el vehículo y ceder el paso al peatón.", "Reducir la velocidad pero continuar si el peatón aún no ha ingresado al carril."], correcta: 1 },
  { id: 76, pregunta: "Sobre el uso del casco protector en la conducción de la motocicleta, es correcto afirmar que:", opciones: ["Solo es obligatorio para el conductor; el acompañante puede decidir si lo usa.", "El uso del casco es obligatorio para el conductor y el acompañante.", "El casco es obligatorio únicamente en carreteras; en zonas urbanas es opcional."], correcta: 1 },
  { id: 77, pregunta: "Las motocicletas al circular por una vía deben hacerlo por el carril de____", opciones: ["Cualquier carril, con preferencia el central.", "El carril del centro en vías de tres o más carriles.", "La derecha."], correcta: 2 },
  { id: 78, pregunta: "Sobre el uso de la bocina del vehículo, es correcto afirmar que:", opciones: ["Puede usarse para saludar a otros conductores o peatones conocidos.", "El conductor únicamente debe utilizar la bocina para evitar situaciones peligrosas.", "Se puede usar la bocina libremente en carreteras y zonas rurales."], correcta: 1 },
  { id: 79, pregunta: "Una línea blanca continua en el sentido longitudinal de una vía, que se coloca en el pavimento, le indica al conductor:", opciones: ["Que puede cruzar al otro carril si realiza la maniobra con precaución.", "Que debe mantenerse dentro de su carril y puede cruzar la línea para adelantar.", "Que está prohibido pasar al otro lado de la línea con algunas excepciones."], correcta: 2 },
  { id: 80, pregunta: "¿Cuál es el número máximo de personas que puede transportar una motocicleta?", opciones: ["Solo el conductor; está prohibido llevar acompañante.", "Hasta dos acompañantes si la moto cuenta con asiento trasero.", "Es igual al número de asientos señalados en la tarjeta de identificación vehicular."], correcta: 2 },
  { id: 81, pregunta: "La acción correcta al abastecer de combustible su vehículo, es:", opciones: ["Mantener el motor encendido para reducir el tiempo de abastecimiento.", "Abstenerse de fumar tanto el conductor como sus acompañantes.", "Es correcto fumar a más de 5 metros de los surtidores."], correcta: 1 },
  { id: 82, pregunta: "Si usted desea realizar una competencia de carreras entre su vehículo y otro vehículo motorizado; para ello puede utilizar:", opciones: ["Una vía pública de poco tráfico en horario de madrugada.", "Ninguna vía; las competencias entre vehículos están totalmente prohibidas.", "Un circuito de carrera, autódromo o pista de aceleración autorizado por la autoridad competente."], correcta: 2 },
  { id: 83, pregunta: "Señale cuál de las siguientes conductas constituye una infracción al tránsito:", opciones: ["Todas las alternativas son correctas.", "Respetar la señal de PARE incluso cuando no hay vehículos.", "Usar las luces bajas en túneles."], correcta: 0 },
  { id: 84, pregunta: "La marcas en el pavimento constituyen un elemento indispensable para la operación vehicular, pues su función es:", opciones: ["Reglamentar la circulación, así como advertir y guiar a los usuarios de la vía.", "Únicamente separar los carriles de circulación en sentidos opuestos.", "Delimitar las zonas de estacionamiento permitido."], correcta: 0 },
  { id: 85, pregunta: "Las marcas en el pavimento de color ________complementan las señales informativas, como por ejemplo las zonas de estacionamiento para personas con movilidad reducida.", opciones: ["Amarillo.", "Azul.", "Blanco."], correcta: 1 },
  { id: 86, pregunta: "La línea central de color amarillo en el pavimento es continua cuando:", opciones: ["No está permitido cruzar al otro carril.", "Está permitido el adelantamiento con precaución.", "La línea discontinua indica el inicio de una zona permitida para adelantar."], correcta: 0 },
  { id: 87, pregunta: "Si un conductor que circula por el carril derecho de una vía se encuentra con las flechas inclinadas que se muestran en la figura, su conducta correcta es:", opciones: ["Continuar por el mismo carril ya que las flechas son solo orientativas.", "Detenerse y esperar instrucciones de la autoridad.", "Cambiarse al carril izquierdo con precaución."], correcta: 2, imagen: "imagenes/pregunta 87.webp" },
  { id: 88, pregunta: "Si durante la conducción vehicular, un efectivo de la Policía de Tránsito le solicita al conductor someterse a una prueba de alcoholemia; la acción correcta del conductor es:", opciones: ["Puede negarse si considera que no ha bebido alcohol.", "Someterse a la prueba de alcoholemia, ya que está obligado a ello ante la solicitud del efectivo de la Policía de Tránsito.", "Puede negarse y esperar la presencia de su abogado."], correcta: 1 },
  { id: 89, pregunta: "¿Cuál de las siguientes conductas no es una infracción de tránsito?", opciones: ["Circular por el carril izquierdo siendo vehículo lento.", "Usar las luces altas en zonas urbanas.", "Detenerse totalmente en una señal de PARE cuando no hay peatones y/o vehículos circulando por la vía transversal."], correcta: 2 },
  { id: 90, pregunta: "Si la persona conduciendo sale de su propiedad y tiene que cruzar la acera e ingresar a una vía, la conducta correcta es:", opciones: ["Ingresar rápidamente a la vía para no obstruir el paso de los peatones.", "Tocar el claxon para alertar a los peatones y luego ingresar a la vía.", "Dar preferencia de paso a los vehículos que circulan por la vía y a los peatones que circulan por la acera."], correcta: 2 },
  { id: 91, pregunta: "¿Qué significa una línea continua blanca pintada entre el carril de la derecha y la berma de una carretera?", opciones: ["Que no se debe conducir atravesándola, al menos que haya una situación de emergencia.", "Que indica el límite de la calzada, pero puede cruzarse para detenerse en la berma.", "Que separa los carriles de circulación y puede cruzarse para adelantar."], correcta: 0 },
  { id: 92, pregunta: "En el caso representado en el siguiente gráfico ¿el vehículo rojo puede rebasar al azul?", opciones: ["Sí puede hacerlo, si la maniobra se realiza con precaución.", "No puede hacerlo.", "Solo puede hacerlo si el azul circula por debajo del límite mínimo de velocidad."], correcta: 1, imagen: "imagenes/pregunta 92.jpg" },
  { id: 93, pregunta: "La siguiente señal (R-17), significa:", opciones: ["Está prohibido el tránsito de vehículos de carga pesada.", "Prohibida la circulación de vehículos automotores.", "Solo está permitida la circulación de vehículos no motorizados."], correcta: 1, imagen: "imagenes/pregunta 93.jpg" },
  { id: 94, pregunta: "Si usted se encuentra conduciendo su vehículo por una vía y antes de cruzar la intersección se encuentra con la señal R-4, esta le indica:", opciones: ["Que debe reducir la velocidad al mínimo antes de cruzar.", "Que tiene preferencia de paso respecto a los vehículos del sentido contrario.", "Que está por ingresar a una vía de sentido contrario y no debe entrar."], correcta: 2, imagen: "imagenes/pregunta 94.jpg" },
  { id: 95, pregunta: "La siguiente señal (P-36), significa:", opciones: ["Presencia de agua en la calzada.", "Zona de baja visibilidad por neblina.", "Superficie deslizante."], correcta: 2, imagen: "imagenes/pregunta 95.webp" },
  { id: 96, pregunta: "La siguiente señal (R-14), significa:", opciones: ["Está permitido circular en ambos sentidos.", "Se puede circular en ambos sentidos si el carril está despejado.", "Circular solo en el sentido indicado por la flecha."], correcta: 2, imagen: "imagenes/pregunta 96.webp" },
  { id: 97, pregunta: "La siguiente señal (P-6) significa:", opciones: ["La proximidad de un cruce o intersección de 2 vías al mismo nivel en ángulo recto.", "La proximidad de una curva pronunciada a la derecha.", "La proximidad de una vía de doble sentido de circulación."], correcta: 0, imagen: "imagenes/pregunta 97.webp" },
  { id: 98, pregunta: "La siguiente señal (R-30C), significa:", opciones: ["Que la velocidad mínima al circular por esa vía es 50 km/h.", "Que al salir de la vía por donde está circulando, la velocidad máxima es 50 km/h.", "Que la velocidad máxima en todo el tramo de la vía es 50 km/h."], correcta: 1, imagen: "imagenes/pregunta 98.webp" },
  { id: 99, pregunta: "La siguiente señal (R-5-4), significa:", opciones: ["Que la intersección contempla giros tangentes a la izquierda en ambos sentidos.", "Que está prohibido girar a la izquierda en la intersección.", "Que solo se permite continuar de frente en la intersección."], correcta: 0, imagen: "imagenes/pregunta 99.webp" },
  { id: 100, pregunta: "La siguiente señal (R-9), significa:", opciones: ["Está prohibido el giro en U en la intersección.", "Que está permitido el giro en U.", "Solo está permitido el giro en U en horas de baja circulación."], correcta: 1, imagen: "imagenes/pregunta 100.webp" },
  { id: 101, pregunta: "La siguiente señal (R-5-2), significa:", opciones: ["Que el carril por donde circula solo permite girar a la izquierda.", "Que el carril solo permite seguir de frente; el giro está prohibido.", "Que el carril por donde circula permite girar a la izquierda o seguir de frente."], correcta: 2, imagen: "imagenes/pregunta 101.webp" },
  { id: 102, pregunta: "La siguiente señal (R-20), significa:", opciones: ["Que los peatones deben circular por la derecha.", "Que los peatones deben circular por la izquierda.", "Que los peatones no pueden circular por esa vía."], correcta: 1, imagen: "imagenes/pregunta 102.webp" },
  { id: 103, pregunta: "Es una conducta que se sanciona:", opciones: ["Respetar la distancia mínima de seguridad entre vehículos.", "Todas las anteriores.", "Ceder el paso al peatón en el paso peatonal."], correcta: 1 },
  { id: 104, pregunta: "La siguiente señal (R-48), significa:", opciones: ["Zona de estacionamiento prohibido.", "Zona de carga y descarga.", "Zona de estacionamiento solo para vehículos de carga."], correcta: 1, imagen: "imagenes/pregunta 104.webp" },
  { id: 105, pregunta: "La siguiente señal (R-49), significa:", opciones: ["Distancia mínima obligatoria entre vehículos.", "Velocidad máxima recomendada.", "Se debe mantener la distancia de seguridad entre vehículos."], correcta: 2, imagen: "imagenes/pregunta 105.webp" },
  { id: 106, pregunta: "La siguiente señal (R-50), significa:", opciones: ["Que todos los carriles tienen preferencia sobre el sentido contrario.", "Que si solo hay un carril no tiene preferencia el que está mirando la señal y debe darle paso al del sentido contrario.", "Que el vehículo que viene en el sentido contrario debe cederle el paso."], correcta: 1, imagen: "imagenes/pregunta  106.webp" },
  { id: 107, pregunta: "La señal (R-5-1), es:", opciones: ["Una señal preventiva de curva.", "Una señal de obligación.", "Una señal de prohibición."], correcta: 1, imagen: "imagenes/pregunta 107.webp" },
  { id: 108, pregunta: "La señal (P-3A), le indica al conductor que:", opciones: ["Hay una curva y contra-curva pronunciada a la derecha.", "Se aproxima a una curva suave a la derecha.", "Hay una curva y contra-curva pronunciada a la izquierda."], correcta: 0, imagen: "imagenes/pregunta 108.webp" },
  { id: 109, pregunta: "La siguiente señal (P-5-1A), le advierte al conductor que:", opciones: ["Se aproxima a una zona de curvas en S a la derecha.", "Se aproxima a una zona con pendiente pronunciada.", "Se aproxima a un camino sinuoso a la izquierda."], correcta: 2, imagen: "imagenes/pregunta 109.webp" },
  { id: 110, pregunta: "La siguiente señal (P-61), le advierte al conductor que:", opciones: ["Se aproxima a una zona de neblina frecuente.", "Está circulando por una curva horizontal.", "Existe presencia de animales cruzando la vía."], correcta: 1, imagen: "imagenes/pregunta 110.webp" },
  { id: 111, pregunta: "La siguiente señal (P-34), le advierte al conductor que:", opciones: ["Se aproxima a un badén.", "Hay una depresión pronunciada en la vía.", "Se aproxima a un reductor de velocidad tipo resalto."], correcta: 0, imagen: "imagenes/pregunta 111.webp" },
  { id: 112, pregunta: "La siguiente señal (P-60), es:", opciones: ["Una señal informativa.", "Una señal reguladora.", "Una señal preventiva."], correcta: 2, imagen: "imagenes/pregunta 112.webp" },
  { id: 113, pregunta: "La siguiente señal (P-46), indica:", opciones: ["Proximidad a un cruce de peatones.", "Zona de cruce de escolares.", "Ciclistas en la vía."], correcta: 2, imagen: "imagenes/pregunta 113.webp" },
  { id: 114, pregunta: "La siguiente señal (P-46-A), indica:", opciones: ["Ubicación de un cruce de ciclistas.", "Zona de cruce de peatones en bicicleta.", "Que nos aproximamos a un cruce de ciclovía."], correcta: 2, imagen: "imagenes/pregunta 114.jpg" },
  { id: 115, pregunta: "La siguiente señal (P-46B), indica:", opciones: ["Presencia de ciclistas en la vía general.", "La ubicación de un cruce de ciclistas.", "Proximidad a un carril exclusivo para bicicletas."], correcta: 1, imagen: "imagenes/pregunta 115.webp" },
  { id: 116, pregunta: "La siguiente señal (P-48), indica:", opciones: ["Proximidad a un cruce escolar.", "Zona con presencia de peatones.", "Ubicación de un paso peatonal regulado por semáforo."], correcta: 1, imagen: "imagenes/pregunta 116.webp" },
  { id: 117, pregunta: "La siguiente señal (P-48A), indica:", opciones: ["Zona con presencia de peatones en la vía.", "Proximidad a un cruce peatonal.", "Ubicación de un paso peatonal elevado."], correcta: 1, imagen: "imagenes/pregunta 117.webp" },
  { id: 118, pregunta: "La siguiente señal (P-48-B), indica:", opciones: ["Ubicación de un cruce peatonal.", "Proximidad a una zona escolar con paso peatonal.", "Zona de cruce peatonal regulada por semáforo."], correcta: 0, imagen: "imagenes/pregunta 118.webp" },
  { id: 119, pregunta: "La siguiente señal (P-49), indica:", opciones: ["Ubicación de un cruce peatonal escolar.", "Zona escolar.", "Proximidad a un centro educativo sin cruce señalizado."], correcta: 1, imagen: "imagenes/pregunta 119.webp" },
  { id: 120, pregunta: "La siguiente señal (P-49A), indica:", opciones: ["Ubicación de una zona escolar.", "Señalización de un cruce escolar ya ubicado.", "Proximidad a un cruce escolar."], correcta: 2, imagen: "imagenes/pregunta 120.webp" },
  { id: 121, pregunta: "La siguiente señal (P-49B), indica:", opciones: ["Ubicación de un cruce escolar.", "Proximidad a una zona escolar.", "Fin de la zona escolar."], correcta: 0, imagen: "imagenes/pregunta 121.png" },
  { id: 122, pregunta: "La siguiente señal (P-50), indica:", opciones: ["Niños jugando.", "Proximidad a una zona de recreación infantil.", "Cruce de escolares próximo."], correcta: 0, imagen: "imagenes/pregunta 122.webp" },
  { id: 123, pregunta: "La siguiente señal (P-51), indica:", opciones: ["Presencia de trabajadores en la vía.", "Presencia de peatones en la calzada.", "Maquinaria agrícola en la vía."], correcta: 2, imagen: "imagenes/pregunta 123.webp" },
  { id: 124, pregunta: "La siguiente señal (P-53), indica:", opciones: ["Zona de paso de personas con movilidad reducida.", "Animales en la vía.", "Presencia de ganado cruzando la vía en zona rural."], correcta: 1, imagen: "imagenes/pregunta 124.webp" },
  { id: 125, pregunta: "La siguiente señal (P-55), indica:", opciones: ["Presencia de una intersección con semáforo próxima.", "Cruce regulado por señal de PARE próximo.", "Proximidad a un semáforo."], correcta: 2, imagen: "imagenes/pregunta 125.webp" },
  { id: 126, pregunta: "La siguiente señal (P-58), le indica:", opciones: ["Que se aproxima a una señal de CEDA EL PASO.", "Que se aproxima a una intersección no regulada.", "Que usted se aproxima a una señal de PARE."], correcta: 2, imagen: "imagenes/pregunat 126.webp" },
  { id: 127, pregunta: "La siguiente señal (P-59), le indica:", opciones: ["Que se aproxima a una señal de PARE.", "Que usted se aproxima a una señal de CEDA EL PASO.", "Que se aproxima a una intersección sin señalización."], correcta: 1 },
  { id: 128, pregunta: "La siguiente señal (P-41), le indica:", opciones: ["Que usted se aproxima a un túnel.", "Que se aproxima a un puente con restricción de altura.", "Que se aproxima a una zona de baja luminosidad."], correcta: 0, imagen: "imagenes/pregunta 128.webp" },
  { id: 129, pregunta: "La siguiente señal (P-45), indica:", opciones: ["Vuelo de aviones a baja altura.", "Zona con presencia de helicópteros.", "Área de aterrizaje de emergencia próxima."], correcta: 0, imagen: "imagenes/pregunta 129.webp" },
  { id: 130, pregunta: "La siguiente señal (P-52), le indica:", opciones: ["Que se aproxima a una zona escolar con semáforo.", "Que se aproxima a una salida de vehículos de bomberos.", "Que hay un cruce de peatones de emergencia próximo."], correcta: 1, imagen: "imagenes/pregunat 130.webp" },
  { id: 131, pregunta: "La siguiente señal (P-66), le indica:", opciones: ["Que se aproxima una zona donde hay ráfagas de viento lateral.", "Que la vía tiene una zona de niebla frecuente.", "Que se aproxima a una zona de lluvias intensas."], correcta: 0, imagen: "imagenes/pregunta 131.webp" },
  { id: 132, pregunta: "La siguiente señal (P-66A), le indica:", opciones: ["Presencia de viento lateral de lado izquierdo.", "Zona de lluvias con arrastre de tierra.", "Que se acerca a una zona de arenamiento en la vía."], correcta: 2, imagen: "imagenes/pregunta 132.webp" },
  { id: 133, pregunta: "Si al conducir su vehículo se encuentra con la señal vertical que se muestra (prohibido girar izquierda con ruta alternativa), usted debe entender que:", opciones: ["Puede girar a la izquierda si no hay vehículos en sentido contrario.", "El giro a la izquierda está prohibido solo en horas pico.", "En la siguiente intersección está prohibido girar a la izquierda y por lo tanto, si desea seguir esa ruta debe tomar el camino alternativo que muestra la señal."], correcta: 2, imagen: "imagenes/pregunta 133.png" },
  { id: 134, pregunta: "Si al conducir su vehículo se encuentra con la señal vertical que se muestra (giro izquierda vuelta manzana), usted debe entender que:", opciones: ["Si quiere girar a la izquierda debe pasar la intersección y dar la vuelta a la manzana.", "Puede girar a la izquierda directamente en la intersección indicada.", "El giro a la izquierda está completamente prohibido en esa zona."], correcta: 0, imagen: "imagenes/pregunta 134.png" },
  { id: 135, pregunta: "La siguiente señal (I-14), significa:", opciones: ["Zona de atención de primeros auxilios.", "Señal de hospital.", "Centro de salud o posta médica próxima."], correcta: 1, imagen: "imagenes/pregunta 135.webp" },
  { id: 136, pregunta: "La siguiente señal (I-31), significa:", opciones: ["Área de estacionamiento de vehículos de emergencia.", "Proximidad de un estacionamiento para emergencias.", "Zona de parada de ambulancias."], correcta: 1, imagen: "imagenes/pregunta 136.webp" },
  { id: 137, pregunta: "La siguiente señal (I-9), significa:", opciones: ["Zona militar.", "Área de entrenamiento militar próxima.", "Prohibición de circulación civil en zona de defensa."], correcta: 0, imagen: "imagenes/pregunta 137.webp" },
  { id: 138, pregunta: "La siguiente señal (I-18), se utiliza para indicar:", opciones: ["Zona de abastecimiento de combustible de emergencia.", "Taller de reparación de vehículos pesados.", "Cercanía a un servicio mecánico."], correcta: 2, imagen: "imagenes/pregunta 138.webp" },
  { id: 139, pregunta: "La siguiente señal (I-19), se utiliza para indicar:", opciones: ["Zona de repostaje de combustible de aviación.", "Estación de carga para vehículos eléctricos.", "Cercanía a un grifo."], correcta: 2, imagen: "imagenes/pregunta 139.webp" },
  { id: 140, pregunta: "La siguiente señal (I-20), se utiliza para indicar:", opciones: ["Zona de cambio de neumáticos de emergencia.", "Cercanía a una llantería.", "Centro de revisión técnica próximo."], correcta: 1, imagen: "imagenes/pregunta 140.webp" },
  { id: 141, pregunta: "La siguiente señal (R-16A), se utiliza para indicar:", opciones: ["Inicio de zona de prohibición de adelantamiento.", "Fin de la restricción de prohibido adelantar.", "Zona donde el adelantamiento requiere precaución especial."], correcta: 1, imagen: "imagenes/pregunta 141.webp" },
  { id: 142, pregunta: "El comportamiento del conductor como usuario de la vía, debe estar orientado a:", opciones: ["Todas las alternativas son correctas.", "Circular a la velocidad más alta posible para reducir el tiempo de viaje.", "Priorizar su propio desplazamiento antes que el de peatones y ciclistas."], correcta: 0 },
  { id: 143, pregunta: "Son considerados usuarios vulnerables de la vía y por tanto merecen especial protección:", opciones: ["Solo conductores de vehículos menores y ciclistas.", "Únicamente peatones mayores de 65 años y niños menores de 12.", "Peatones, niños, adultos mayores, personas con movilidad reducida, ciclistas."], correcta: 2 },
  { id: 144, pregunta: "La siguiente señal (P-61), muestra:", opciones: ["Marcas de reducción de carril en la vía.", "Marcas de zona de estacionamiento en curva.", "Delineadores de curva, que guían al conductor."], correcta: 2, imagen: "imagenes/pregunta 144.webp" },
  { id: 145, pregunta: "El conductor está ____ a las pruebas que le solicite el Efectivo de la Policía Nacional del Perú, asignado al control del tránsito, para determinar su estado de intoxicación por alcohol, drogas, estupefacientes u otros tóxicos", opciones: ["Obligado - someterse.", "Facultado - negarse si no se siente en estado de ebriedad.", "Autorizado - rechazar si no ha consumido alcohol en las últimas horas."], correcta: 0 },
  { id: 146, pregunta: "Ante un conductor con evidente discapacidad física, la cual no figura en el rubro de restricciones de su licencia de conducir, procede:", opciones: ["Permitirle continuar conduciendo ya que su licencia está vigente.", "Solo notificarle verbalmente que debe actualizar su licencia.", "Que la Policía de Tránsito intervenga a dicho conductor y que la autoridad que expidió la licencia de conducir ordene su reexaminación."], correcta: 2 },
  { id: 147, pregunta: "Es una obligación general de tránsito que, los ___________ circulen respetando los mensajes de ________, las instrucciones de los Efectivos de la Policía de Tránsito y el mandato de las normas legales y reglamentarias correspondientes.", opciones: ["Los usuarios de la vía pública - los dispositivos de control de tránsito.", "Los conductores solamente - las señales verticales.", "Los conductores y peatones - las marcas del pavimento únicamente."], correcta: 0 },
  { id: 148, pregunta: "Marque la afirmación incorrecta:", opciones: ["Las motocicletas pueden compartir un mismo carril con otro vehículo al circular.", "El conductor de moto debe usar casco tanto en zonas urbanas como en carreteras.", "Las motocicletas deben circular por el carril derecho de la vía."], correcta: 0 },
  { id: 149, pregunta: "¿Si al conducir por una avenida se encuentra con una señal en la vía que indica un límite máximo de 50 km/h, sin embargo, conforme a lo dispuesto en la norma el límite máximo de velocidad en dicha vía es de 60 km/h; usted:", opciones: ["Circula a 60 km/h ya que la norma tiene mayor jerarquía que la señal.", "Puede circular entre 50 y 60 km/h según su criterio.", "Debe obedecer la señal de velocidad instalada en la vía."], correcta: 2 },
  { id: 150, pregunta: "Indique la conducta permitida:", opciones: ["Conducir a exceso de velocidad en horario nocturno con escaso tráfico.", "Usar el carril de emergencia para adelantar en una congestión.", "El estacionamiento de un vehículo de emergencia en un lugar no permitido, si ello fuera imprescindible."], correcta: 2 },
  { id: 151, pregunta: "Se considera el abandono de un vehículo cuando:", opciones: ["El vehículo está estacionado en un lugar permitido en la vía pública, pero sin conductor y por un tiempo mayor de 48 horas.", "El vehículo está estacionado en zona prohibida por más de 2 horas.", "El vehículo queda inmovilizado en la vía por falla mecánica sin triángulos de seguridad."], correcta: 0 },
  { id: 152, pregunta: "El servicio de taxi en motos lineales:", opciones: ["No está permitido.", "Está permitido solo en zonas rurales o fuera de las ciudades.", "Está permitido si el conductor cuenta con licencia de categoría A-IIb."], correcta: 0 },
  { id: 153, pregunta: "Sobre la emisión vehicular de sustancias contaminantes, marque la opción correcta:", opciones: ["Solo los vehículos diésel tienen restricción de emisiones contaminantes.", "Está prohibida, en un índice superior al límite máximo que permite la norma.", "Las motos lineales están exentas de la norma de emisiones contaminantes."], correcta: 1 },
  { id: 154, pregunta: "La autoridad competente, puede prohibir o restringir ____ en determinadas vías públicas.", opciones: ["Solo el estacionamiento en vías de alta circulación.", "Cuando la situación lo justifique - la circulación o estacionamiento de vehículos.", "Únicamente la circulación de vehículos pesados en zonas urbanas."], correcta: 1 },
  { id: 155, pregunta: "La detención de un vehículo debe efectuarse:", opciones: ["En cualquier lugar de la vía si la detención es breve.", "En el carril izquierdo si el conductor va a girar a la izquierda.", "En el sentido de la circulación y en el carril derecho de la vía."], correcta: 2 },
  { id: 156, pregunta: "En caso de un accidente de tránsito con daños personales y/o materiales los participantes deben:", opciones: ["Abandonar el lugar si los daños son solo materiales y ambas partes están de acuerdo.", "Solicitar la intervención de la autoridad policial.", "Resolver el incidente directamente entre las partes para agilizar el tráfico."], correcta: 1 },
  { id: 157, pregunta: "La faculta y autoriza la circulación del vehículo por la vía pública, identifica el bien, y, por ende, al titular responsable de las acciones que deriven de su propiedad.", opciones: ["Placa Única Nacional de Rodaje.", "La licencia de conducir del propietario del vehículo.", "El SOAT vigente del vehículo."], correcta: 0 },
  { id: 158, pregunta: "¿Después de qué tiempo de haber cometido la misma infracción se llama reincidencia y es sancionada con el doble de la multa establecida?", opciones: ["24 meses.", "12 meses.", "6 meses."], correcta: 1 },
  { id: 159, pregunta: "Si a un conductor infractor le suspendieron su licencia de conducir, éste se encuentra facultado para:", opciones: ["Conducir solo en zonas urbanas y a baja velocidad durante la suspensión.", "Ninguna de las alternativas es correcta.", "Conducir vehículos no motorizados como bicicletas."], correcta: 1 },
  { id: 160, pregunta: "Las ____ tienen por función informar a los usuarios sobre los servicios generales existentes próximos a la vía, tales como teléfono, hospedaje, restaurante, primeros auxilios, estación de combustibles, talleres, y otros.", opciones: ["Señales de servicios generales.", "Señales informativas de ruta.", "Señales preventivas de servicios."], correcta: 0 },
  { id: 161, pregunta: "¿Constituye una infracción tramitar el duplicado de una licencia de conducir que se encuentra retenida?", opciones: ["Si, constituye una infracción.", "No, es un derecho del conductor obtener un duplicado en cualquier momento.", "Solo es infracción si la retención fue por conducir en estado de ebriedad."], correcta: 0 },
  { id: 162, pregunta: "Las marcas en el pavimento constituyen la señalización _____y se emplean para _________ la circulación.", opciones: ["Vertical - advertir.", "Horizontal - reglamentar.", "Preventiva - guiar."], correcta: 1 },
  { id: 163, pregunta: "Ciclista es a ciclovía como:", opciones: ["Conductor - calzada.", "Peatón - berma.", "Motociclista - calzada exclusiva."], correcta: 0 },
  { id: 164, pregunta: "La siguiente señal (P-15), se utiliza para advertir al conductor:", opciones: ["La proximidad de una intersección rotatoria (óvalo o rotonda).", "La proximidad de una intersección en forma de T.", "La proximidad de una intersección con semáforo."], correcta: 0, imagen: "imagenes/pregunta 164.webp" },
  { id: 165, pregunta: "La siguiente señal (P-31A), indica:", opciones: ["Proximidad a un carril que termina.", "La proximidad del final de la vía.", "Inicio de una vía sin salida."], correcta: 1, imagen: "imagenes/pregunta 165.webp" },
  { id: 166, pregunta: "Es una línea transversal a la calzada, que indica al conductor que debe detener completamente el vehículo, no debiendo sobrepasar el inicio de la indicada línea:", opciones: ["Línea de cruce peatonal.", "Línea de pare.", "Línea de carril de desaceleración."], correcta: 1 },
  { id: 167, pregunta: "Los semáforos son:", opciones: ["Señales verticales que regulan el flujo de vehículos en intersecciones.", "Dispositivos de control del tránsito que tienen por finalidad regular y controlar el tránsito vehicular, motorizado y no motorizado, y el peatonal, a través de las indicaciones de las luces respectivas.", "Marcas en el pavimento que indican zonas de detención obligatoria."], correcta: 1 },
  { id: 168, pregunta: "La conducción requiere un alto nivel de atención, pues existen distracciones que pueden ocasionar accidentes de tránsito, como, por ejemplo:", opciones: ["Revisar el velocímetro con frecuencia para no exceder el límite.", "Todas las alternativas son correctas.", "Usar los espejos retrovisores para observar el tráfico."], correcta: 1 },
  { id: 169, pregunta: "¿Influye la somnolencia en la capacidad de conducir?", opciones: ["No, siempre y cuando el conductor lleve ventana abierta y música.", "Solo influye si el conductor lleva más de 4 horas seguidas manejando.", "Si, pues el conductor tomará decisiones lentas que lo inducirán a cometer errores."], correcta: 2 },
  { id: 170, pregunta: "¿Cuál es la acción correcta del conductor, según las normas de tránsito, en la situación que plantea el siguiente gráfico?", opciones: ["Tocar el claxon para que el peatón se apresure en cruzar.", "Continuar la marcha si el peatón aún no ha ingresado al carril.", "Dar preferencia de paso al peatón para que cruce la calzada."], correcta: 2, imagen: "imagenes/pregunta 170.png" },
  { id: 171, pregunta: "¿En cuál de las siguientes opciones, los factores mencionados contribuyen a una colisión vehicular?", opciones: ["Pavimento húmedo, neumáticos desgastados, cansancio.", "Lluvia ligera, velocidad adecuada, conductor descansado.", "Uso de luces altas, exceso de carga, baja velocidad."], correcta: 0 },
  { id: 172, pregunta: "La ____ es la parte de una carretera o camino contigua a la calzada, no habilitada para la circulación de vehículos y destinada eventualmente a la detención de vehículos en emergencia y circulación de peatones.", opciones: ["Ciclovía.", "Berma.", "Acera o vereda."], correcta: 1 },
  { id: 173, pregunta: "Es una parte de la vía destinada a la circulación de vehículos y eventualmente al cruce de peatones y animales.", opciones: ["La berma.", "La calzada.", "La acera o vereda."], correcta: 1 },
  { id: 174, pregunta: "Es una parte de la vía destinada al uso de peatones", opciones: ["La calzada.", "La acera.", "La berma."], correcta: 1 },
  { id: 175, pregunta: "Son señales que regulan el tránsito:", opciones: ["Las señales preventivas y las informativas.", "Los semáforos y las señales preventivas.", "Las señales verticales y las marcas en la calzada o señales horizontales."], correcta: 2 },
  { id: 176, pregunta: "El conductor que en una vía urbana va a girar a la izquierda, a la derecha o en 'U' debe hacer la señal respectiva con la luz direccional, por lo menos:", opciones: ["10 metros antes de realizar la maniobra.", "30 metros antes de realizar la maniobra.", "20 metros antes de realizar la maniobra."], correcta: 2 },
  { id: 177, pregunta: "Si usted está conduciendo por una carretera y va girar a la izquierda, debe realizar la señal respectiva con la luz direccional por lo menos:", opciones: ["20 metros antes de realizar la maniobra.", "30 metros antes de realizar la maniobra.", "50 metros antes de realizar la maniobra."], correcta: 1 },
  { id: 178, pregunta: "¿La licencia de la Clase B, permite conducir autos?", opciones: ["No.", "Sí, pero solo automóviles de hasta 1600 cc.", "Sí, todo tipo de vehículos livianos."], correcta: 0 },
  { id: 179, pregunta: "El siguiente gráfico muestra:", opciones: ["Zona de trabajo con señalización vial temporal.", "Marcas de carril de emergencia en zona escolar.", "Señalización de tránsito vertical y horizontal en una zona escolar."], correcta: 2, imagen: "imagenes/pregunta 179.png" },
  { id: 180, pregunta: "Las ____ canalizadoras, tiene por función conformar las islas canalizadoras del tránsito automotor en una ____.", opciones: ["Flechas - avenida.", "Líneas - intersección.", "Marcas - rotonda."], correcta: 1 },
  { id: 181, pregunta: "Si al conducir en una intersección se encuentra con las siguientes marcas en el pavimento (malla ortogonal de color amarillo), significa:", opciones: ["Que no puede detener el vehículo dentro del área de intersección.", "Que puede detenerse brevemente si está esperando girar a la izquierda.", "Que debe reducir la velocidad y cruzar la intersección con precaución."], correcta: 0 },
  { id: 182, pregunta: "De acuerdo al siguiente gráfico, es correcto afirmar que:", opciones: ["La zona de no adelantar termina donde inician las líneas discontinuas.", "El adelantamiento está permitido en toda la extensión de la vía graficada.", "La zona de no adelantar inicia con las líneas amarillas continuas."], correcta: 2, imagen: "imagenes/pregunta 182.png" },
  { id: 183, pregunta: "Cuál de las siguientes alternativas, no es una infracción de tránsito:", opciones: ["Usar el celular mientras se conduce.", "Detenerse en luz verde, para ceder el paso a un peatón.", "Circular en sentido contrario al permitido."], correcta: 1 },
  { id: 184, pregunta: "Existe infracción al tránsito cuya sanción sea nunca más obtener una licencia de conducir?", opciones: ["No, la inhabilitación máxima es de 3 años.", "Si existe, y una de ellas es por conducir con presencia de alcohol en mayor grado al permitido y participar en un accidente de tránsito.", "No, toda sanción tiene una duración determinada y luego puede recuperarse la licencia."], correcta: 1 },
  { id: 185, pregunta: "Los ____ y las ____ requieren un carril completo para circular con seguridad.", opciones: ["Todas las anteriores.", "Motociclistas - bicicletas.", "Vehículos pesados - buses."], correcta: 0 },
  { id: 186, pregunta: "El conductor de un vehículo debe reducir la velocidad, siempre que se encuentre en los siguientes casos:", opciones: ["En zonas con pavimento seco y buena visibilidad.", "Al circular por una vía recta con buen estado de la calzada.", "En intersecciones, curvas, túneles, puentes."], correcta: 2 },
  { id: 187, pregunta: "El pasajero de una motocicleta debe saber:", opciones: ["Que puede apoyarse en el conductor para mantener el equilibrio.", "Todas las anteriores.", "Que no necesita usar casco si va a baja velocidad."], correcta: 1 },
  { id: 188, pregunta: "En la relación 'conductores de vehículos menores' (por ejemplo, una motocicleta) y 'conductores de vehículos mayores' (por ejemplo un auto sedan), la afirmación correcta es:", opciones: ["Los conductores de vehículos menores tienen las obligaciones y derechos aplicables a los conductores de vehículos mayores, excepto aquellos que por su naturaleza no les son aplicables.", "Los conductores de vehículos menores tienen menos obligaciones que los de vehículos mayores.", "Los conductores de vehículos menores están exentos de las normas de tránsito aplicables a vehículos mayores."], correcta: 0 },
  { id: 189, pregunta: "Antes de iniciar la conducción de una motocicleta, el conductor debe:", opciones: ["Verificar solo el nivel de combustible y el estado de los frenos.", "Todas las alternativas son correctas.", "Solo revisar las luces y los neumáticos."], correcta: 1, imagen: "imagenes/pregunta 189.webp" },
  { id: 190, pregunta: "El equipo de protección más importante al conducir una motocicleta, es:", opciones: ["Casco.", "Guantes y chaqueta de protección.", "Botas de conducción."], correcta: 0 },
  { id: 191, pregunta: "La posición correcta del motociclista en la conducción es:", opciones: ["Las alternativas b y c son correctas.", "Con la espalda recta y los codos ligeramente flexionados únicamente.", "Con las rodillas abiertas hacia afuera para mayor estabilidad."], correcta: 0 },
  { id: 192, pregunta: "La siguiente afirmación: 'el motociclista que se encuentra conduciendo en un carril, no debe permitir que otros vehículos intenten forzarlo a moverse hacia un costado del mismo', es:", opciones: ["Verdadera.", "Falsa, porque el motociclista debe ceder espacio a vehículos mayores.", "Verdadera solo en carreteras; en zonas urbanas el motociclista debe ceder el carril."], correcta: 0 },
  { id: 193, pregunta: "La agilidad de la moto _____debe ser __________ para ir en _______ entre vehículos:", opciones: ["Siempre - aprovechada - paralelo.", "A veces - utilizada - fila.", "Nunca - aprovechada - zig zag."], correcta: 2 },
  { id: 194, pregunta: "La conducción eficiente, tiene como beneficio:", opciones: ["Cuidado del medioambiente, ahorro de combustible o energía.", "Mayor velocidad de desplazamiento en carreteras.", "Reducción del tiempo de viaje en zonas urbanas."], correcta: 0 },
  { id: 195, pregunta: "La siguiente señal de autorización, le indica que:", opciones: ["Permite el giro a la izquierda en una intersección con semáforo en luz roja.", "Solo puede girar a la izquierda si no hay vehículos en la vía transversal.", "El giro a la izquierda está permitido solo con luz verde del semáforo."], correcta: 0, imagen: "imagenes/pregunta 195.png" },
  { id: 196, pregunta: "Es una técnica de conducción eficiente, y por tanto permite la reducción del consumo de combustible, así como de la contaminación ambiental:", opciones: ["Conducir siempre en la marcha más baja para tener mayor control del vehículo.", "Acelerar y frenar de forma brusca para reducir el tiempo de desplazamiento.", "Las alternativas a y b son correctas."], correcta: 2 },
  { id: 197, pregunta: "La posición correcta de los pies al conducir una motocicleta es:", opciones: ["Colocar de manera recta el arco de los pies en los apoyapiés.", "Apoyar las puntas de los pies en los apoyapiés con los talones elevados.", "Apoyar los talones en los apoyapiés con las puntas de los pies hacia arriba."], correcta: 0 },
  { id: 198, pregunta: "Para un frenado seguro de la motocicleta (en un frenado usual como, al entrar a una curva, al llegar a una intersección, etc.), se debe utilizar:", opciones: ["Solo el freno posterior para evitar el vuelco frontal.", "El freno delantero y el freno posterior.", "Solo el freno delantero ya que ofrece mayor potencia de frenado."], correcta: 1 },
  { id: 199, pregunta: "Al realizar el cambio de carril, la conducta correcta es:", opciones: ["Las alternativas a y c son correctas.", "Cambiar de carril de forma rápida y sin señalizar si la vía está despejada.", "Esperar que el carril esté completamente libre antes de encender la direccional."], correcta: 0 },
  { id: 200, pregunta: "Mientras se conduce para alcanzar la velocidad deseada, la aceleración debe ser:", opciones: ["Brusca, para alcanzar rápidamente la velocidad de la vía.", "Constante al máximo para reducir el consumo de combustible.", "Progresiva."], correcta: 2 },
];